  2→
  3→import { useCallback, useEffect, useRef, useState } from 'react';
  4→
  5→export type VoiceState = 'dormant' | 'listening' | 'thinking' | 'speaking' | 'followup';
  6→
  7→export interface VoiceEngineOptions {
  8→  onTranscript: (text: string) => void;
  9→  onTTSStart?: () => void;
 10→  onTTSEnd?: () => void;
 11→  followUpWindowMs?: number;
 12→  ttsUrl?: string;
 13→  autoStart?: boolean;
 14→}
 15→
 16→export interface VoiceEngineReturn {
 17→  voiceState: VoiceState;
 18→  interim: string;
 19→  micLevel: number;
 20→  ttsLevel: number;
 21→  supported: boolean;
 22→  toggle: () => void;
 23→  speakText: (text: string) => Promise<void>;
 24→  stopSpeaking: () => void;
 25→  wakeUp: () => void;
 26→}
 27→
 28→const WAKE_WORDS = ['mega', 'omega'];
 29→const FOLLOW_UP_MS = 25_000;
 30→const MIN_SPEECH_CHARS = 3;
 31→
 32→export function useVoiceEngine({
 33→  onTranscript,
 34→  onTTSStart,
 35→  onTTSEnd,
 36→  followUpWindowMs = FOLLOW_UP_MS,
 37→  ttsUrl = '/api/tts',
 38→  autoStart = true,
 39→}: VoiceEngineOptions): VoiceEngineReturn {
 40→  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
 41→  const [interim, setInterim] = useState('');
 42→  const [micLevel, setMicLevel] = useState(0);
 43→  const [ttsLevel, setTtsLevel] = useState(0);
 44→  const [supported, setSupported] = useState(false);
 45→
 46→  const stateRef = useRef<VoiceState>('dormant');
 47→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 48→  const recogRef = useRef<any>(null);
 49→  const followUpTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
 50→  const audioCtxRef = useRef<AudioContext | null>(null);
 51→  const micStreamRef = useRef<MediaStream | null>(null);
 52→  const analyserRef = useRef<AnalyserNode | null>(null);
 53→  const micAnimRef = useRef<number | null>(null);
 54→  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
 55→  const ttsAnalyserRef = useRef<AnalyserNode | null>(null);
 56→  const ttsAnimRef = useRef<number | null>(null);
 57→  const mutedRef = useRef(false);
 58→
 59→  // Keep stateRef in sync
 60→  const setState = useCallback((s: VoiceState) => {
 61→    stateRef.current = s;
 62→    setVoiceState(s);
 63→  }, []);
 64→
 65→  // ── Mic level analyzer ─────────────────────────────────────────────────────
 66→  const startMicAnalyzer = useCallback(async () => {
 67→    try {
 68→      if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
 69→        audioCtxRef.current = new AudioContext();
 70→      }
 71→      if (!micStreamRef.current) {
 72→        micStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
 73→      }
 74→      const src = audioCtxRef.current.createMediaStreamSource(micStreamRef.current);
 75→      analyserRef.current = audioCtxRef.current.createAnalyser();
 76→      analyserRef.current.fftSize = 128;
 77→      src.connect(analyserRef.current);
 78→
 79→      const tick = () => {
 80→        if (!analyserRef.current) return;
 81→        const buf = new Uint8Array(analyserRef.current.frequencyBinCount);
 82→        analyserRef.current.getByteFrequencyData(buf);
 83→        const avg = buf.reduce((a, b) => a + b, 0) / buf.length;
 84→        setMicLevel(Math.min(avg / 80, 1));
 85→        micAnimRef.current = requestAnimationFrame(tick);
 86→      };
 87→      tick();
 88→    } catch { /* mic denied — voice still works via recognition */ }
 89→  }, []);
 90→
 91→  const stopMicAnalyzer = useCallback(() => {
 92→    if (micAnimRef.current) cancelAnimationFrame(micAnimRef.current);
 93→    setMicLevel(0);
 94→  }, []);
 95→
 96→  // ── Follow-up window ────────────────────────────────────────────────────────
 97→  const clearFollowUp = useCallback(() => {
 98→    if (followUpTimer.current) clearTimeout(followUpTimer.current);
 99→  }, []);
100→
101→  const enterFollowUp = useCallback(() => {
102→    setState('followup');
103→    clearFollowUp();
104→    followUpTimer.current = setTimeout(() => {
105→      if (stateRef.current === 'followup') setState('dormant');
106→    }, followUpWindowMs);
107→  }, [setState, clearFollowUp, followUpWindowMs]);
108→
109→  // ── TTS playback ────────────────────────────────────────────────────────────
110→  const stopSpeaking = useCallback(() => {
111→    ttsSourceRef.current?.stop();
112→    ttsSourceRef.current = null;
113→    if (ttsAnimRef.current) cancelAnimationFrame(ttsAnimRef.current);
114→    setTtsLevel(0);
115→  }, []);
116→
117→  const speakText = useCallback(async (text: string): Promise<void> => {
118→    if (!text?.trim()) { enterFollowUp(); return; }
119→    stopSpeaking();
120→    setState('speaking');
121→    onTTSStart?.();
122→
123→    try {
124→      const res = await fetch(ttsUrl, {
125→        method: 'POST',
126→        headers: { 'Content-Type': 'application/json' },
127→        body: JSON.stringify({ text: text.slice(0, 2000) }),
128→      });
129→      const data = await res.json();
130→
131→      if (!data.audio) throw new Error('No audio returned');
132→
133→      // Decode base64 WAV
134→      const raw = atob(data.audio);
135→      const bytes = new Uint8Array(raw.length);
136→      for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
137→
138→      const ctx = new AudioContext();
139→      const buffer = await ctx.decodeAudioData(bytes.buffer);
140→
141→      // TTS level analyzer
142→      const analyser = ctx.createAnalyser();
143→      analyser.fftSize = 128;
144→      ttsAnalyserRef.current = analyser;
145→
146→      const src = ctx.createBufferSource();
147→      src.buffer = buffer;
148→      src.connect(analyser);
149→      analyser.connect(ctx.destination);
150→      ttsSourceRef.current = src;
151→
152→      const tick = () => {
153→        if (!ttsAnalyserRef.current) return;
154→        const buf = new Uint8Array(ttsAnalyserRef.current.frequencyBinCount);
155→        ttsAnalyserRef.current.getByteFrequencyData(buf);
156→        const avg = buf.reduce((a, b) => a + b, 0) / buf.length;
157→        setTtsLevel(Math.min(avg / 80, 1));
158→        ttsAnimRef.current = requestAnimationFrame(tick);
159→      };
160→      tick();
161→
162→      src.start();
163→      src.onended = () => {
164→        if (ttsAnimRef.current) cancelAnimationFrame(ttsAnimRef.current);
165→        setTtsLevel(0);
166→        ctx.close();
167→        onTTSEnd?.();
168→        enterFollowUp();
169→      };
170→    } catch (e) {
171→      console.warn('[VoiceEngine] TTS error:', e);
172→      onTTSEnd?.();
173→      enterFollowUp();
174→    }
175→  }, [ttsUrl, stopSpeaking, setState, enterFollowUp, onTTSStart, onTTSEnd]);
176→
177→  // ── Speech recognition ──────────────────────────────────────────────────────
178→  const stopRecognition = useCallback(() => {
179→    try { recogRef.current?.stop(); } catch { /* ignore */ }
180→  }, []);
181→
182→  const startRecognition = useCallback(() => {
183→    const SR = (typeof window !== 'undefined')
184→      // eslint-disable-next-line @typescript-eslint/no-explicit-any
185→      ? ((window as any).SpeechRecognition ?? (window as any).webkitSpeechRecognition)
186→      : null;
187→    if (!SR) return;
188→
189→    stopRecognition();
190→
191→    const r = new SR();
192→    r.continuous = true;
193→    r.interimResults = true;
194→    r.lang = 'en-US';
195→    r.maxAlternatives = 1;
196→    recogRef.current = r;
197→
198→    let finalBuffer = '';
199→    let silenceTimer: ReturnType<typeof setTimeout> | null = null;
200→
201→    const resetSilence = () => {
202→      if (silenceTimer) clearTimeout(silenceTimer);
203→      silenceTimer = setTimeout(() => {
204→        if (finalBuffer.trim().length >= MIN_SPEECH_CHARS &&
205→            (stateRef.current === 'listening' || stateRef.current === 'followup')) {
206→          const text = finalBuffer.trim();
207→          finalBuffer = '';
208→          setInterim('');
209→          stopMicAnalyzer();
210→          setState('thinking');
211→          onTranscript(text);
212→        }
213→      }, 1400);
214→    };
215→
216→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
217→    r.onresult = (e: any) => {
218→      let interimText = '';
219→      let newFinal = '';
220→
221→      for (let i = e.resultIndex; i < e.results.length; i++) {
222→        const t = e.results[i][0].transcript;
223→        if (e.results[i].isFinal) newFinal += t + ' ';
224→        else interimText += t;
225→      }
226→
227→      if (newFinal) {
228→        finalBuffer += newFinal;
229→        resetSilence();
230→      }
231→
232→      setInterim((finalBuffer + interimText).trim());
233→
234→      // Wake word check when dormant
235→      if (stateRef.current === 'dormant') {
236→        const all = (finalBuffer + interimText).toLowerCase();
237→        if (WAKE_WORDS.some(w => all.includes(w))) {
238→          finalBuffer = '';
239→          setInterim('');
240→          setState('listening');
241→          startMicAnalyzer();
242→        }
243→      }
244→    };
245→
246→    r.onspeechstart = () => {
247→      if (stateRef.current === 'dormant') return;
248→      if (stateRef.current === 'followup') {
249→        clearFollowUp();
250→        setState('listening');
251→        startMicAnalyzer();
252→      }
253→    };
254→
255→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
256→    r.onerror = (e: any) => {
257→      if (e.error === 'no-speech' || e.error === 'aborted') return;
258→      console.warn('[VoiceEngine] Recognition error:', e.error);
259→    };
260→
261→    r.onend = () => {
262→      // Auto-restart unless we're muted or thinking/speaking
263→      if (!mutedRef.current &&
264→          stateRef.current !== 'thinking' &&
265→          stateRef.current !== 'speaking') {
266→        setTimeout(() => { if (!mutedRef.current) startRecognition(); }, 200);
267→      }
268→    };
269→
270→    try { r.start(); } catch { /* already running */ }
271→  }, [stopRecognition, stopMicAnalyzer, setState, startMicAnalyzer, onTranscript, clearFollowUp]);
272→
273→  // ── Public controls ─────────────────────────────────────────────────────────
274→  const wakeUp = useCallback(() => {
275→    clearFollowUp();
276→    setState('listening');
277→    startMicAnalyzer();
278→  }, [setState, clearFollowUp, startMicAnalyzer]);
279→
280→  const toggle = useCallback(() => {
281→    if (stateRef.current === 'dormant') {
282→      mutedRef.current = false;
283→      wakeUp();
284→      startRecognition();
285→    } else {
286→      mutedRef.current = true;
287→      stopRecognition();
288→      stopSpeaking();
289→      stopMicAnalyzer();
290→      clearFollowUp();
291→      setState('dormant');
292→    }
293→  }, [wakeUp, startRecognition, stopRecognition, stopSpeaking, stopMicAnalyzer, clearFollowUp, setState]);
294→
295→  // ── Init ────────────────────────────────────────────────────────────────────
296→  useEffect(() => {
297→    const hasSR = typeof window !== 'undefined' &&
298→      !!((window as any).SpeechRecognition ?? (window as any).webkitSpeechRecognition);
299→    setSupported(hasSR);
300→    if (!hasSR || !autoStart) return;
301→
302→    // Small delay to let the page settle
303→    const t = setTimeout(() => {
304→      mutedRef.current = false;
305→      startRecognition();
306→      // Start in listening mode immediately
307→      setState('listening');
308→      startMicAnalyzer();
309→    }, 800);
310→
311→    return () => {
312→      clearTimeout(t);
313→      mutedRef.current = true;
314→      stopRecognition();
315→      stopMicAnalyzer();
316→      clearFollowUp();
317→    };
318→    // eslint-disable-next-line react-hooks/exhaustive-deps
319→  }, []);
320→
321→  // When thinking ends (canvasState goes back to idle from parent), restart recognition
322→  useEffect(() => {
323→    if (voiceState === 'listening' || voiceState === 'followup') {
324→      if (!recogRef.current) startRecognition();
325→    }
326→  }, [voiceState, startRecognition]);
327→
328→  return { voiceState, interim, micLevel, ttsLevel, supported, toggle, speakText, stopSpeaking, wakeUp };
329→}
