  1→'use client';
  2→
  3→import { useEffect, useRef } from 'react';
  4→import type { VoiceState } from '@/hooks/useVoiceEngine';
  5→import s from './VoiceOrb.module.css';
  6→
  7→interface VoiceOrbProps {
  8→  voiceState: VoiceState;
  9→  micLevel?: number;   // 0-1
 10→  ttsLevel?: number;   // 0-1
 11→  thinking?: boolean;  // OmegA is processing
 12→  size?: number;
 13→}
 14→
 15→export default function VoiceOrb({
 16→  voiceState,
 17→  micLevel = 0,
 18→  ttsLevel = 0,
 19→  thinking = false,
 20→  size = 220,
 21→}: VoiceOrbProps) {
 22→  const canvasRef = useRef<HTMLCanvasElement>(null);
 23→  const frameRef = useRef<number>(0);
 24→  const phaseRef = useRef(0);
 25→
 26→  const activeLevel = voiceState === 'speaking' ? ttsLevel : micLevel;
 27→  const isActive = voiceState !== 'dormant';
 28→
 29→  useEffect(() => {
 30→    const canvas = canvasRef.current;
 31→    if (!canvas) return;
 32→    const ctx = canvas.getContext('2d');
 33→    if (!ctx) return;
 34→
 35→    const W = size * 2; // retina
 36→    canvas.width = W;
 37→    canvas.height = W;
 38→    const C = W / 2;
 39→    const R = C * 0.32; // core radius
 40→
 41→    const draw = () => {
 42→      phaseRef.current += 0.018;
 43→      const ph = phaseRef.current;
 44→      const lv = activeLevel;
 45→
 46→      ctx.clearRect(0, 0, W, W);
 47→
 48→      // ── Outer ambient glow ──────────────────────────────────────────────────
 49→      const ambientR = C * 0.85 + lv * C * 0.12;
 50→      const ambient = ctx.createRadialGradient(C, C, R * 0.5, C, C, ambientR);
 51→
 52→      if (thinking) {
 53→        ambient.addColorStop(0, 'rgba(228,184,74,0.12)');
 54→        ambient.addColorStop(0.5, 'rgba(228,184,74,0.04)');
 55→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 56→      } else if (voiceState === 'listening' || voiceState === 'followup') {
 57→        ambient.addColorStop(0, 'rgba(99,102,241,0.18)');
 58→        ambient.addColorStop(0.5, 'rgba(139,92,246,0.06)');
 59→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 60→      } else if (voiceState === 'speaking') {
 61→        ambient.addColorStop(0, 'rgba(196,181,253,0.20)');
 62→        ambient.addColorStop(0.5, 'rgba(139,92,246,0.07)');
 63→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 64→      } else {
 65→        ambient.addColorStop(0, 'rgba(99,102,241,0.06)');
 66→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 67→      }
 68→      ctx.fillStyle = ambient;
 69→      ctx.fillRect(0, 0, W, W);
 70→
 71→      // ── Pulse rings (3 rings, offset phase) ────────────────────────────────
 72→      const ringCount = 3;
 73→      for (let i = 0; i < ringCount; i++) {
 74→        const offset = (i / ringCount) * Math.PI * 2;
 75→        const pulse = Math.sin(ph * 0.8 + offset) * 0.5 + 0.5;
 76→        const ringR = R * (1.5 + i * 0.55) + lv * R * 0.6 * (1 - i * 0.2);
 77→        const alpha = isActive
 78→          ? (thinking ? 0.55 : 0.35 + pulse * 0.25) * (1 - i * 0.2)
 79→          : 0.08 + pulse * 0.04;
 80→
 81→        let color: string;
 82→        if (thinking) color = `rgba(228,184,74,${alpha})`;
 83→        else if (voiceState === 'speaking') color = `rgba(196,181,253,${alpha})`;
 84→        else if (voiceState === 'followup') color = `rgba(99,210,190,${alpha})`;
 85→        else color = `rgba(139,92,246,${alpha})`;
 86→
 87→        ctx.beginPath();
 88→        ctx.arc(C, C, ringR, 0, Math.PI * 2);
 89→        ctx.strokeStyle = color;
 90→        ctx.lineWidth = thinking ? 1.5 : 1.0 + lv * 1.5;
 91→        ctx.stroke();
 92→      }
 93→
 94→      // ── Waveform ring (when active) ─────────────────────────────────────────
 95→      if (isActive && lv > 0.02) {
 96→        const waveR = R * 1.35 + lv * R * 0.4;
 97→        const points = 128;
 98→        ctx.beginPath();
 99→        for (let p = 0; p <= points; p++) {
100→          const angle = (p / points) * Math.PI * 2 - Math.PI / 2;
101→          const wave = Math.sin(angle * 8 + ph * 3) * lv * R * 0.18
102→                     + Math.sin(angle * 5 - ph * 2) * lv * R * 0.10;
103→          const r = waveR + wave;
104→          const x = C + Math.cos(angle) * r;
105→          const y = C + Math.sin(angle) * r;
106→          p === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
107→        }
108→        ctx.closePath();
109→        const waveAlpha = 0.4 + lv * 0.4;
110→        ctx.strokeStyle = thinking
111→          ? `rgba(228,184,74,${waveAlpha})`
112→          : voiceState === 'speaking'
113→          ? `rgba(196,181,253,${waveAlpha})`
114→          : `rgba(99,102,241,${waveAlpha})`;
115→        ctx.lineWidth = 1.5;
116→        ctx.stroke();
117→      }
118→
119→      // ── Rotating arc (thinking) ─────────────────────────────────────────────
120→      if (thinking) {
121→        ctx.save();
122→        ctx.translate(C, C);
123→        ctx.rotate(ph * 2.5);
124→        ctx.beginPath();
125→        ctx.arc(0, 0, R * 2.0, 0, Math.PI * 1.2);
126→        ctx.strokeStyle = 'rgba(228,184,74,0.7)';
127→        ctx.lineWidth = 2;
128→        ctx.lineCap = 'round';
129→        ctx.stroke();
130→        ctx.rotate(Math.PI);
131→        ctx.beginPath();
132→        ctx.arc(0, 0, R * 2.0, 0, Math.PI * 0.5);
133→        ctx.strokeStyle = 'rgba(228,184,74,0.35)';
134→        ctx.lineWidth = 1.5;
135→        ctx.stroke();
136→        ctx.restore();
137→      }
138→
139→      // ── Core glow ───────────────────────────────────────────────────────────
140→      const coreGlow = ctx.createRadialGradient(C, C, 0, C, C, R * 1.3);
141→      const breathe = Math.sin(ph * 0.7) * 0.5 + 0.5;
142→
143→      if (thinking) {
144→        coreGlow.addColorStop(0, `rgba(255,230,130,${0.25 + breathe * 0.15})`);
145→        coreGlow.addColorStop(0.4, `rgba(228,184,74,${0.15 + breathe * 0.10})`);
146→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
147→      } else if (voiceState === 'speaking') {
148→        coreGlow.addColorStop(0, `rgba(220,200,255,${0.22 + lv * 0.2})`);
149→        coreGlow.addColorStop(0.4, `rgba(139,92,246,${0.14 + lv * 0.1})`);
150→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
151→      } else if (voiceState === 'listening') {
152→        coreGlow.addColorStop(0, `rgba(140,120,255,${0.20 + lv * 0.25})`);
153→        coreGlow.addColorStop(0.4, `rgba(99,102,241,${0.10 + lv * 0.15})`);
154→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
155→      } else if (voiceState === 'followup') {
156→        coreGlow.addColorStop(0, `rgba(99,210,190,${0.18 + breathe * 0.08})`);
157→        coreGlow.addColorStop(0.4, `rgba(16,185,129,${0.10})`);
158→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
159→      } else {
160→        coreGlow.addColorStop(0, `rgba(99,102,241,${0.10 + breathe * 0.05})`);
161→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
162→      }
163→      ctx.fillStyle = coreGlow;
164→      ctx.beginPath();
165→      ctx.arc(C, C, R * 1.3, 0, Math.PI * 2);
166→      ctx.fill();
167→
168→      frameRef.current = requestAnimationFrame(draw);
169→    };
170→
171→    draw();
172→    return () => cancelAnimationFrame(frameRef.current);
173→  }, [voiceState, thinking, activeLevel, isActive, size]);
174→
175→  const stateClass = thinking ? s.thinking
176→    : voiceState === 'listening' ? s.listening
177→    : voiceState === 'speaking' ? s.speaking
178→    : voiceState === 'followup' ? s.followup
179→    : s.dormant;
180→
181→  return (
182→    <div className={`${s.orbWrap} ${stateClass}`} style={{ width: size, height: size }}>
183→      <canvas ref={canvasRef} className={s.canvas} style={{ width: size, height: size }} />
184→      <div className={s.symbol}>Ω</div>
185→    </div>
186→  );
187→}
