  1→"use client";
  2→
  3→import { useEffect, useRef } from "react";
  4→
  5→export type CanvasState = "idle" | "thinking" | "responding";
  6→
  7→interface Particle {
  8→  x: number; y: number;
  9→  vx: number; vy: number;
 10→  size: number;
 11→  opacity: number;
 12→  rgb: string;
 13→  phase: number;
 14→  phaseSpeed: number;
 15→}
 16→
 17→interface FieldLine {
 18→  pts: number[];   // x0,y0, cx1,cy1, cx2,cy2, x1,y1
 19→  vel: number[];   // dx for each control point
 20→  opacity: number;
 21→}
 22→
 23→function hex(h: string): string {
 24→  const r = parseInt(h.slice(1, 3), 16);
 25→  const g = parseInt(h.slice(3, 5), 16);
 26→  const b = parseInt(h.slice(5, 7), 16);
 27→  return `${r},${g},${b}`;
 28→}
 29→
 30→const COLORS = ["#3b4fd8", "#6d4ff5", "#9b7cfa", "#c4b5fd", "#818cf8"].map(hex);
 31→
 32→export default function OmegaCanvas({ state }: { state: CanvasState }) {
 33→  const ref = useRef<HTMLCanvasElement>(null);
 34→  const stateRef = useRef(state);
 35→  useEffect(() => { stateRef.current = state; }, [state]);
 36→
 37→  useEffect(() => {
 38→    const canvas = ref.current;
 39→    if (!canvas) return;
 40→    const ctx = canvas.getContext("2d");
 41→    if (!ctx) return;
 42→
 43→    let raf: number;
 44→    let W = 0, H = 0;
 45→    let frame = 0;
 46→
 47→    const isMobile = window.innerWidth < 768;
 48→
 49→    const resize = () => {
 50→      W = canvas.width = window.innerWidth;
 51→      H = canvas.height = window.innerHeight;
 52→    };
 53→    window.addEventListener("resize", resize);
 54→    resize();
 55→
 56→    // Fewer particles on mobile to preserve battery and frame rate
 57→    const COUNT = isMobile ? 55 : 140;
 58→    const particles: Particle[] = Array.from({ length: COUNT }, () => ({
 59→      x: Math.random() * W,
 60→      y: Math.random() * H,
 61→      vx: (Math.random() - 0.5) * 0.35,
 62→      vy: (Math.random() - 0.5) * 0.35,
 63→      size: Math.random() * 1.8 + 0.4,
 64→      opacity: Math.random() * 0.55 + 0.1,
 65→      rgb: COLORS[Math.floor(Math.random() * COLORS.length)],
 66→      phase: Math.random() * Math.PI * 2,
 67→      phaseSpeed: 0.008 + Math.random() * 0.018,
 68→    }));
 69→
 70→    // Field lines
 71→    const LINES = 10;
 72→    const lines: FieldLine[] = Array.from({ length: LINES }, () => ({
 73→      pts: [
 74→        Math.random() * W, Math.random() * H,
 75→        Math.random() * W, Math.random() * H,
 76→        Math.random() * W, Math.random() * H,
 77→        Math.random() * W, Math.random() * H,
 78→      ],
 79→      vel: Array.from({ length: 8 }, () => (Math.random() - 0.5) * 0.25),
 80→      opacity: Math.random() * 0.07 + 0.02,
 81→    }));
 82→
 83→    const draw = () => {
 84→      raf = requestAnimationFrame(draw);
 85→      frame++;
 86→
 87→      const s = stateRef.current;
 88→      const speed = s === "thinking" ? 2.8 : s === "responding" ? 1.6 : 1;
 89→      const glow = s === "thinking" ? 0.18 + 0.12 * Math.sin(frame * 0.08) : s === "responding" ? 0.08 : 0;
 90→
 91→      // Trailing clear
 92→      ctx.fillStyle = "rgba(2, 2, 12, 0.18)";
 93→      ctx.fillRect(0, 0, W, H);
 94→
 95→      // Central pulse glow when thinking
 96→      if (glow > 0) {
 97→        const g = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, Math.min(W, H) * 0.55);
 98→        g.addColorStop(0, `rgba(99,60,220,${glow})`);
 99→        g.addColorStop(0.5, `rgba(60,40,180,${glow * 0.4})`);
100→        g.addColorStop(1, "rgba(0,0,0,0)");
101→        ctx.fillStyle = g;
102→        ctx.fillRect(0, 0, W, H);
103→      }
104→
105→      // Field lines
106→      for (const fl of lines) {
107→        for (let i = 0; i < fl.pts.length; i++) {
108→          fl.pts[i] += fl.vel[i] * speed;
109→          if (fl.pts[i] < -200 || fl.pts[i] > (i % 2 === 0 ? W : H) + 200) fl.vel[i] *= -1;
110→        }
111→        const [x0, y0, cx1, cy1, cx2, cy2, x1, y1] = fl.pts;
112→        const grad = ctx.createLinearGradient(x0, y0, x1, y1);
113→        const op = fl.opacity * (s === "thinking" ? 2.2 : s === "responding" ? 1.4 : 1);
114→        grad.addColorStop(0, `rgba(80,50,220,0)`);
115→        grad.addColorStop(0.5, `rgba(110,70,240,${op})`);
116→        grad.addColorStop(1, `rgba(80,50,220,0)`);
117→        ctx.beginPath();
118→        ctx.moveTo(x0, y0);
119→        ctx.bezierCurveTo(cx1, cy1, cx2, cy2, x1, y1);
120→        ctx.strokeStyle = grad;
121→        ctx.lineWidth = 1;
122→        ctx.stroke();
123→      }
124→
125→      // Connections
126→      const maxDist = s === "thinking" ? 110 : 85;
127→      for (let i = 0; i < particles.length; i++) {
128→        for (let j = i + 1; j < particles.length; j++) {
129→          const dx = particles[i].x - particles[j].x;
130→          const dy = particles[i].y - particles[j].y;
131→          const d = Math.sqrt(dx * dx + dy * dy);
132→          if (d < maxDist) {
133→            const a = (1 - d / maxDist) * 0.12 * (s === "thinking" ? 2.5 : 1);
134→            ctx.beginPath();
135→            ctx.moveTo(particles[i].x, particles[i].y);
136→            ctx.lineTo(particles[j].x, particles[j].y);
137→            ctx.strokeStyle = `rgba(120,80,255,${a})`;
138→            ctx.lineWidth = 0.5;
139→            ctx.stroke();
140→          }
141→        }
142→      }
143→
144→      // Particles
145→      for (const p of particles) {
146→        p.x += p.vx * speed;
147→        p.y += p.vy * speed;
148→        p.phase += p.phaseSpeed * speed;
149→        if (p.x < 0) p.x = W;
150→        if (p.x > W) p.x = 0;
151→        if (p.y < 0) p.y = H;
152→        if (p.y > H) p.y = 0;
153→
154→        const pulse = 0.5 + 0.5 * Math.sin(p.phase);
155→        const op = p.opacity * pulse * (s === "thinking" ? 1.5 : 1);
156→        const sz = p.size * (0.7 + 0.3 * pulse);
157→
158→        // Soft glow
159→        const grd = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, sz * 5);
160→        grd.addColorStop(0, `rgba(${p.rgb},${op})`);
161→        grd.addColorStop(1, `rgba(${p.rgb},0)`);
162→        ctx.beginPath();
163→        ctx.arc(p.x, p.y, sz * 5, 0, Math.PI * 2);
164→        ctx.fillStyle = grd;
165→        ctx.fill();
166→
167→        // Core
168→        ctx.beginPath();
169→        ctx.arc(p.x, p.y, sz, 0, Math.PI * 2);
170→        ctx.fillStyle = `rgba(${p.rgb},${Math.min(op * 2, 1)})`;
171→        ctx.fill();
172→      }
173→
174→      // Arc sparks when thinking
175→      if (s === "thinking" && frame % 8 === 0) {
176→        const cx = W / 2 + (Math.random() - 0.5) * 60;
177→        const cy = H / 2 + (Math.random() - 0.5) * 60;
178→        ctx.beginPath();
179→        ctx.arc(cx, cy, Math.random() * 80 + 20, 0, Math.PI * 2 * Math.random());
180→        ctx.strokeStyle = `rgba(180,140,255,${Math.random() * 0.15})`;
181→        ctx.lineWidth = 0.5;
182→        ctx.stroke();
183→      }
184→    };
185→
186→    draw();
187→    return () => {
188→      cancelAnimationFrame(raf);
189→      window.removeEventListener("resize", resize);
190→    };
191→  }, []);
192→
193→  return (
194→    <canvas
195→      ref={ref}
196→      style={{
197→        position: "fixed", inset: 0,
198→        width: "100%", height: "100%",
199→        zIndex: 0, pointerEvents: "none",
200→        background: "#02020c",
201→        willChange: "transform",
202→      }}
203→    />
204→  );
205→}
206→

