  1→'use client';
  2→
  3→import { useState, useRef, useEffect, useCallback } from 'react';
  4→import dynamic from 'next/dynamic';
  5→import { chatStream } from '@/lib/api';
  6→import { useVoiceEngine } from '@/hooks/useVoiceEngine';
  7→import Sidebar from '@/components/Sidebar/Sidebar';
  8→import s from './page.module.css';
  9→
 10→const VoiceOrb = dynamic(() => import('@/components/VoiceOrb/VoiceOrb'), { ssr: false });
 11→
 12→interface Msg {
 13→  role: 'user' | 'omega';
 14→  text: string;
 15→  timestamp?: string;
 16→  provider?: string;
 17→}
 18→
 19→const STATE_LABELS: Record<string, string> = {
 20→  dormant:   'Say "Mega" to wake',
 21→  listening: 'Listening...',
 22→  thinking:  'Thinking...',
 23→  speaking:  'Speaking...',
 24→  followup:  "I'm here — go ahead",
 25→};
 26→
 27→export default function Home() {
 28→  const [messages, setMessages]       = useState<Msg[]>([]);
 29→  const [error, setError]             = useState<string | null>(null);
 30→  const [sessionId, setSessionId]     = useState<string | null>(null);
 31→  const [sessionList, setSessionList] = useState<{id:string;created_at:string;preview:string}[]>([]);
 32→  const [sidebarOpen, setSidebarOpen] = useState(false);
 33→  const [provider, setProvider]       = useState<string | null>(null);
 34→  const [textInput, setTextInput]     = useState('');
 35→  const [showText, setShowText]       = useState(false);
 36→  const [processing, setProcessing]   = useState(false);
 37→
 38→  const pendingTTS = useRef<string | null>(null);
 39→  const feedRef    = useRef<HTMLDivElement>(null);
 40→
 41→  useEffect(() => {
 42→    const saved = localStorage.getItem('omega_session');
 43→    if (saved) setSessionId(saved);
 44→  }, []);
 45→
 46→  const refreshSessions = useCallback(() => {
 47→    fetch('/api/sessions').then(r => r.json())
 48→      .then(d => { if (Array.isArray(d)) setSessionList(d); })
 49→      .catch(console.error);
 50→  }, []);
 51→
 52→  useEffect(() => { refreshSessions(); }, [refreshSessions]);
 53→
 54→  useEffect(() => {
 55→    feedRef.current?.scrollTo({ top: feedRef.current.scrollHeight, behavior: 'smooth' });
 56→  }, [messages, processing]);
 57→
 58→  const sendMessage = useCallback(async (text: string) => {
 59→    if (!text.trim() || processing) return;
 60→    setError(null);
 61→    setProcessing(true);
 62→    pendingTTS.current = null;
 63→
 64→    const history = [...messages];
 65→    setMessages(prev => [...prev, { role: 'user', text, timestamp: new Date().toISOString() }]);
 66→
 67→    let fullReply = '';
 68→    try {
 69→      const res = await chatStream(
 70→        { user: text, history, sessionId: sessionId ?? undefined },
 71→        chunk => {
 72→          fullReply += chunk;
 73→          setMessages(prev => {
 74→            const u = [...prev];
 75→            const last = u[u.length - 1];
 76→            if (last.role === 'user') {
 77→              u.push({ role: 'omega', text: chunk, timestamp: new Date().toISOString() });
 78→            } else {
 79→              u[u.length - 1] = { ...last, text: last.text + chunk };
 80→            }
 81→            return u;
 82→          });
 83→        },
 84→        () => {}
 85→      );
 86→      if (res.sessionId && !sessionId) {
 87→        setSessionId(res.sessionId);
 88→        localStorage.setItem('omega_session', res.sessionId);
 89→      }
 90→      if (res.provider) {
 91→        setProvider(res.provider);
 92→        setMessages(prev => {
 93→          const u = [...prev];
 94→          const last = u[u.length - 1];
 95→          if (last.role === 'omega') u[u.length - 1] = { ...last, provider: res.provider };
 96→          return u;
 97→        });
 98→      }
 99→      refreshSessions();
100→      pendingTTS.current = fullReply;
101→    } catch (err) {
102→      setError(err instanceof Error ? err.message : String(err));
103→    } finally {
104→      setProcessing(false);
105→    }
106→  }, [processing, messages, sessionId, refreshSessions]);
107→
108→  const voice = useVoiceEngine({ onTranscript: sendMessage });
109→
110→  useEffect(() => {
111→    if (!processing && pendingTTS.current) {
112→      const t = pendingTTS.current;
113→      pendingTTS.current = null;
114→      voice.speakText(t);
115→    }
116→  }, [processing, voice]);
117→
118→  const handleTextSend = useCallback(() => {
119→    const t = textInput.trim();
120→    if (!t) return;
121→    setTextInput('');
122→    setShowText(false);
123→    sendMessage(t);
124→  }, [textInput, sendMessage]);
125→
126→  const loadSession = async (id: string) => {
127→    try {
128→      const res = await fetch(`/api/sessions/${id}`);
129→      const data = await res.json();
130→      if (Array.isArray(data)) {
131→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
132→        setMessages(data.map((m: any) => ({ role: m.role, text: m.content, timestamp: m.created_at })));
133→        setSessionId(id);
134→        localStorage.setItem('omega_session', id);
135→        setSidebarOpen(false);
136→      }
137→    } catch (err) { console.error(err); }
138→  };
139→
140→  const startNewChat = () => {
141→    setMessages([]);
142→    setSessionId(null);
143→    setProvider(null);
144→    localStorage.removeItem('omega_session');
145→    setSidebarOpen(false);
146→  };
147→
148→  const vs = processing ? 'thinking' : voice.voiceState;
149→  const stateLabel = processing ? 'Thinking...' : (STATE_LABELS[voice.voiceState] ?? '');
150→
151→  return (
152→    <div className={s.root}>
153→      <div className={s.stars} aria-hidden />
154→
155→      <Sidebar
156→        sessions={sessionList}
157→        activeSessionId={sessionId}
158→        onNewChat={startNewChat}
159→        onSelectSession={loadSession}
160→        isOpen={sidebarOpen}
161→        onToggle={() => setSidebarOpen(o => !o)}
162→      />
163→
164→      <div className={`${s.main} ${sidebarOpen ? s.mainShifted : ''}`}>
165→
166→        <header className={s.topBar}>
167→          <button className={s.menuBtn} onClick={() => setSidebarOpen(o => !o)} aria-label="History">
168→            <span /><span /><span />
169→          </button>
170→          <div className={s.brand}>
171→            <span className={s.brandGlyph}>Ω</span>
172→            <span className={s.brandName}>OmegA</span>
173→          </div>
174→          <div className={s.topRight}>
175→            {provider && <span className={s.badge}>{provider.split('-')[0]}</span>}
176→            <span className={`${s.dot} ${vs === 'thinking' ? s.dotThink : vs !== 'dormant' ? s.dotLive : ''}`} />
177→          </div>
178→        </header>
179→
180→        <div className={s.stage}>
181→          <div className={s.orbClick} onClick={voice.toggle} title="Toggle voice">
182→            <VoiceOrb
183→              voiceState={voice.voiceState}
184→              micLevel={voice.micLevel}
185→              ttsLevel={voice.ttsLevel}
186→              thinking={processing}
187→            />
188→          </div>
189→          <p className={`${s.stateLabel} ${s['sl_' + vs]}`}>{stateLabel}</p>
190→          {voice.interim && (
191→            <div className={s.interim}><span>{voice.interim}</span></div>
192→          )}
193→        </div>
194→
195→        {(messages.length > 0 || processing) && (
196→          <div className={s.feed} ref={feedRef}>
197→            {messages.map((m, i) => (
198→              <div key={i} className={`${s.msg} ${m.role === 'user' ? s.msgUser : s.msgOmega}`}>
199→                {m.role === 'omega' && <span className={s.msgGlyph}>Ω</span>}
200→                <span className={s.msgText}>{m.text}</span>
201→              </div>
202→            ))}
203→            {processing && (
